// ============================================================
// WF-06: POST-CONSULTA — Encuesta de satisfacción
// Cron cada 1 hora: detecta turnos elegibles y envía encuesta
// ============================================================

const helpers = this.helpers;
const SUPABASE_URL = $env.SUPABASE_URL;
const SUPABASE_KEY = $env.SUPABASE_SERVICE_KEY;
const WA_TOKEN = $env.META_WHATSAPP_TOKEN;
const PHONE_ID = '963190063548521';

// ── Supabase helpers ──
async function supaQuery(query) {
  try {
    const r = await helpers.httpRequest({
      method: 'POST',
      url: `${SUPABASE_URL}/rest/v1/rpc/`,
      headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}`, 'Content-Type': 'application/json' },
      body: JSON.stringify(query)
    });
    return r;
  } catch (e) { return []; }
}

async function supaGet(table, params) {
  try {
    return await helpers.httpRequest({
      method: 'GET',
      url: `${SUPABASE_URL}/rest/v1/${table}`,
      qs: params || {},
      headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}` }
    });
  } catch (e) { return []; }
}

async function supaUpdate(table, filters, data) {
  try {
    await helpers.httpRequest({
      method: 'PATCH',
      url: `${SUPABASE_URL}/rest/v1/${table}`,
      qs: filters,
      headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}`, 'Content-Type': 'application/json' },
      body: JSON.stringify({ ...data, updated_at: new Date().toISOString() })
    });
  } catch (e) {}
}

async function supaUpdateConv(phone, estado, contexto) {
  const d = { estado, updated_at: new Date().toISOString() };
  if (contexto !== undefined) d.contexto = contexto;
  await supaUpdate('consultorio_conversaciones', { telefono_wa: `eq.${phone}` }, d);
}

// ── WhatsApp helpers ──
async function sendText(phone, text) {
  await helpers.httpRequest({
    method: 'POST',
    url: `https://graph.facebook.com/v21.0/${PHONE_ID}/messages`,
    headers: { 'Authorization': `Bearer ${WA_TOKEN}`, 'Content-Type': 'application/json' },
    body: JSON.stringify({ messaging_product: 'whatsapp', to: phone, type: 'text', text: { body: text } })
  });
}

async function sendList(phone, text, buttonText, sections) {
  await helpers.httpRequest({
    method: 'POST',
    url: `https://graph.facebook.com/v21.0/${PHONE_ID}/messages`,
    headers: { 'Authorization': `Bearer ${WA_TOKEN}`, 'Content-Type': 'application/json' },
    body: JSON.stringify({
      messaging_product: 'whatsapp', to: phone, type: 'interactive',
      interactive: { type: 'list', body: { text }, action: { button: buttonText.substring(0,20), sections } }
    })
  });
}

// ── Buscar turnos elegibles ──
// Trigger híbrido:
// - Si check_in_at existe: check_in_at + duracion + 30min < NOW
// - Si no: fecha_hora + duracion + 2hs < NOW
// Filtro: estado IN (confirmado, presente), encuesta_enviada = false

const now = new Date();

const turnos = await supaGet('consultorio_turnos', {
  encuesta_enviada: 'eq.false',
  estado: 'in.(confirmado,presente)',
  select: 'id,paciente_id,profesional_id,fecha_hora,check_in_at'
});

if (!turnos?.length) {
  return [{ json: { action: 'no_turnos_elegibles', count: 0 } }];
}

const resultados = [];

for (const turno of turnos) {
  // Obtener duración del profesional
  const profs = await supaGet('consultorio_profesionales', {
    id: `eq.${turno.profesional_id}`,
    select: 'duracion_turno_min,nombre,especialidad'
  });
  const prof = profs?.[0];
  if (!prof) continue;

  const durMin = prof.duracion_turno_min || 15;

  // Calcular si es elegible
  let elegible = false;
  if (turno.check_in_at) {
    // check_in_at + duracion + 30min < NOW
    const checkInTime = new Date(turno.check_in_at).getTime();
    const umbral = checkInTime + (durMin + 30) * 60 * 1000;
    elegible = now.getTime() > umbral;
  } else {
    // fecha_hora + duracion + 2hs < NOW
    const turnoTime = new Date(turno.fecha_hora).getTime();
    const umbral = turnoTime + (durMin + 120) * 60 * 1000;
    elegible = now.getTime() > umbral;
  }

  if (!elegible) continue;

  // Obtener datos del paciente
  const pacs = await supaGet('consultorio_pacientes', {
    id: `eq.${turno.paciente_id}`,
    select: 'nombre,telefono_wa'
  });
  const pac = pacs?.[0];
  if (!pac) continue;

  const nombre = pac.nombre.split(' ')[0];
  const phone = pac.telefono_wa;

  // Enviar encuesta por WhatsApp (List Message con 5 opciones)
  try {
    await sendList(
      phone,
      `¡Hola ${nombre}! ¿Cómo fue tu consulta con ${prof.nombre}?\n\nCalificala del 1 al 5:`,
      'Calificar',
      [{
        title: 'Calificación',
        rows: [
          { id: 'calif_1', title: '1 ⭐', description: 'Muy mala' },
          { id: 'calif_2', title: '2 ⭐⭐', description: 'Mala' },
          { id: 'calif_3', title: '3 ⭐⭐⭐', description: 'Regular' },
          { id: 'calif_4', title: '4 ⭐⭐⭐⭐', description: 'Buena' },
          { id: 'calif_5', title: '5 ⭐⭐⭐⭐⭐', description: 'Excelente' }
        ]
      }]
    );

    // Marcar encuesta enviada
    await supaUpdate('consultorio_turnos', { id: `eq.${turno.id}` }, { encuesta_enviada: true });

    // Actualizar estado de conversación
    // Obtenemos el contexto actual para no perder datos
    const convs = await supaGet('consultorio_conversaciones', {
      telefono_wa: `eq.${phone}`,
      select: 'contexto'
    });
    const ctxActual = convs?.[0]?.contexto || {};
    const nuevoCtx = {
      ...ctxActual,
      turno_feedback_id: turno.id,
      profesionalId: turno.profesional_id,
      profesionalNombre: prof.nombre,
      especialidad: prof.especialidad
    };
    await supaUpdateConv(phone, 'esperando_calificacion', nuevoCtx);

    resultados.push({ phone, turnoId: turno.id, prof: prof.nombre, status: 'encuesta_enviada' });
  } catch (e) {
    resultados.push({ phone, turnoId: turno.id, status: 'error', error: e.message });
  }
}

return [{ json: { action: 'encuestas_enviadas', count: resultados.length, resultados } }];

